import java.time.Instant;
import java.time.OffsetDateTime;

import org.json.JSONArray;
import org.json.JSONObject;

List expiredContainers = new ArrayList();

JSONArray containerListJSONArray = new JSONArray(project.getProperty("container.list"));

for (int i = 0; i < containerListJSONArray.length(); i++) {
	JSONObject containerJSONObject = containerListJSONArray.getJSONObject(i);

	String containerName = containerJSONObject.getString("name");

	if (!containerName.contains("lfr-qa-poshi-test")) {
		continue;
	}

	JSONObject propertiesJSONObject = containerJSONObject.getJSONObject("properties");

	OffsetDateTime offsetDateTime = OffsetDateTime.parse(propertiesJSONObject.getString("lastModified"));

	Instant instant = offsetDateTime.toInstant();

	if (((System.currentTimeMillis() - instant.toEpochMilli()) / (1000 * 60 * 60)) > 12) {
		expiredContainers.add(containerName);
	}
}

String expiredContainersString = expiredContainers.toString();

expiredContainersString = expiredContainersString.replaceAll(" ", "");

project.setProperty("expired.containers", expiredContainersString.substring(1, expiredContainersString.length() - 1));
